        {/* Main content */}
        <main className="flex-1 min-w-0 overflow-y-auto px-4 md:px-10 py-8">
          {!entry || !content ? (
            <div className="max-w-3xl">
              <h1 className="text-2xl font-bold mb-3">{t("common.docsNotFound")}</h1>
