        {statusText}
      </span>
      <span className="w-[180px] text-sm text-zinc-400 light:text-slate-600 truncate">
        {job.lastRunAt ? `${new Date(job.lastRunAt).toLocaleString()}` : `—`}
      </span>
      <span className="w-[180px] text-sm text-zinc-400 light:text-slate-600 truncate">
